-- Drop everything
drop table if exists persona_evolution_log cascade;
drop table if exists narrative_events cascade;
drop table if exists player_chemistry cascade;
drop table if exists coaching_staff cascade;
drop table if exists persona_definitions cascade;
drop table if exists gm_profiles cascade;
drop table if exists trade_players cascade;
drop table if exists trades cascade;
drop table if exists game_log cascade;
drop table if exists rosters cascade;
drop table if exists seasons cascade;
drop table if exists players cascade;
drop table if exists teams cascade;

-- ============================================================
-- SCHEMA
-- ============================================================

create table teams (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  city text,
  wins int default 0,
  losses int default 0,
  color_primary text default '#1A1A18',
  color_secondary text default '#F5F0E8',
  difficulty text default 'rebuilding'
    check (difficulty in ('rebuilding', 'contender', 'dynasty')),
  flavor_text text
);

create table players (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  age int,
  position text default 'SF'
    check (position in ('PG', 'SG', 'SF', 'PF', 'C')),
  points int, assists int, rebounds int, speed int, defense int,
  overall int,
  tier text default 'normal',
  potential int default 50 check (potential between 0 and 100),
  morale int default 75 check (morale between 0 and 100),
  persona_category text
    check (persona_category in (
      'raw_diamond','quiet_assassin','locker_room_cancer','underdog',
      'fading_legend','franchise_cornerstone','mercenary','late_bloomer'
    )),
  persona_sub text,
  is_revealed boolean default false,
  trait_tags text[] default '{}',
  contract_years int default 1,
  salary int default 1000000
);

create table rosters (
  id uuid primary key default gen_random_uuid(),
  team_id uuid references teams(id) on delete cascade,
  player_id uuid references players(id) on delete cascade,
  role text default 'bench',
  is_dev_league boolean default false,
  minutes_avg int default 0,
  assigned_at timestamp default now()
);

create table seasons (
  id uuid primary key default gen_random_uuid(),
  season_number int default 1,
  games_played int default 0,
  games_per_season int default 12,
  is_active boolean default true
);

create table game_log (
  id uuid primary key default gen_random_uuid(),
  season_id uuid references seasons(id) on delete cascade,
  home_team_id uuid references teams(id),
  away_team_id uuid references teams(id),
  home_score int, away_score int,
  played_at timestamp default now()
);

create table trades (
  id uuid primary key default gen_random_uuid(),
  team_a_id uuid references teams(id),
  team_b_id uuid references teams(id),
  traded_at timestamp default now()
);

create table trade_players (
  id uuid primary key default gen_random_uuid(),
  trade_id uuid references trades(id) on delete cascade,
  player_id uuid references players(id),
  from_team_id uuid references teams(id),
  to_team_id uuid references teams(id)
);

create table gm_profiles (
  id uuid primary key default gen_random_uuid(),
  team_id uuid references teams(id) on delete cascade,
  manager_name text not null,
  rep_archetype text default 'unknown'
    check (rep_archetype in ('unknown','player_developer','loyalty_gm','win_now','rebuilder','mercenary_gm')),
  loyalty_score int default 50 check (loyalty_score between 0 and 100),
  dev_score int default 50 check (dev_score between 0 and 100),
  win_now_score int default 50 check (win_now_score between 0 and 100),
  seasons_managed int default 0,
  created_at timestamp default now()
);

create table persona_definitions (
  id uuid primary key default gen_random_uuid(),
  category text not null
    check (category in (
      'raw_diamond','quiet_assassin','locker_room_cancer','underdog',
      'fading_legend','franchise_cornerstone','mercenary','late_bloomer'
    )),
  sub_persona text not null,
  playstyle_effect text,
  coach_response text check (coach_response in ('receptive','neutral','resistant','volatile')),
  chemistry_affinity text[],
  chemistry_clash text[],
  evolution_trigger text,
  dev_modifier numeric(3,2) default 1.0,
  morale_modifier numeric(3,2) default 1.0,
  unique (category, sub_persona)
);

create table player_chemistry (
  id uuid primary key default gen_random_uuid(),
  player_a_id uuid references players(id) on delete cascade,
  player_b_id uuid references players(id) on delete cascade,
  team_id uuid references teams(id) on delete cascade,
  chemistry_score int default 50 check (chemistry_score between 0 and 100),
  relationship_type text default 'neutral'
    check (relationship_type in ('bond','neutral','tension','rivalry','mentor')),
  seasons_together int default 0,
  updated_at timestamp default now(),
  unique (player_a_id, player_b_id, team_id)
);

create table coaching_staff (
  id uuid primary key default gen_random_uuid(),
  team_id uuid references teams(id) on delete cascade,
  name text not null,
  specialty text not null
    check (specialty in ('veteran_presence','player_development','motivator','x_and_o','player_coach','shooting','playmaking','development','defense','conditioning','iq')),
  dev_boost numeric(3,2) default 1.1,
  level int default 1 check (level between 1 and 5),
  salary int default 500000,
  hired_at timestamp default now()
);

create table narrative_events (
  id uuid primary key default gen_random_uuid(),
  season_id uuid references seasons(id) on delete cascade,
  team_id uuid references teams(id) on delete cascade,
  player_id uuid references players(id) on delete set null,
  event_type text not null
    check (event_type in (
      'demand','breakout','regression','mentor_bond','trade_request',
      'contract_holdout','rivalry','locker_room_incident','community_moment','retirement_warning'
    )),
  description text, choice_a text, choice_b text,
  outcome_a text, outcome_b text,
  chosen_option text check (chosen_option in ('a','b',null)),
  is_resolved boolean default false,
  triggered_at timestamp default now()
);

create table persona_evolution_log (
  id uuid primary key default gen_random_uuid(),
  player_id uuid references players(id) on delete cascade,
  season_id uuid references seasons(id) on delete set null,
  old_category text, old_sub_persona text,
  new_category text, new_sub_persona text,
  trigger_reason text, gm_action text,
  evolved_at timestamp default now()
);

-- Indexes
create index idx_rosters_team on rosters(team_id);
create index idx_rosters_player on rosters(player_id);
create index idx_rosters_dev_league on rosters(is_dev_league);
create index idx_players_persona on players(persona_category, persona_sub);
create index idx_narrative_events_team_season on narrative_events(team_id, season_id);
create index idx_narrative_events_unresolved on narrative_events(is_resolved) where is_resolved = false;
create index idx_chemistry_team on player_chemistry(team_id);
create index idx_evolution_player on persona_evolution_log(player_id);

-- RLS
alter table teams enable row level security;
alter table players enable row level security;
alter table rosters enable row level security;
alter table seasons enable row level security;
alter table game_log enable row level security;
alter table trades enable row level security;
alter table trade_players enable row level security;
alter table gm_profiles enable row level security;
alter table persona_definitions enable row level security;
alter table player_chemistry enable row level security;
alter table coaching_staff enable row level security;
alter table narrative_events enable row level security;
alter table persona_evolution_log enable row level security;

create policy "public access" on teams for all using (true) with check (true);
create policy "public access" on players for all using (true) with check (true);
create policy "public access" on rosters for all using (true) with check (true);
create policy "public access" on seasons for all using (true) with check (true);
create policy "public access" on game_log for all using (true) with check (true);
create policy "public access" on trades for all using (true) with check (true);
create policy "public access" on trade_players for all using (true) with check (true);
create policy "public access" on gm_profiles for all using (true) with check (true);
create policy "public access" on persona_definitions for all using (true) with check (true);
create policy "public access" on player_chemistry for all using (true) with check (true);
create policy "public access" on coaching_staff for all using (true) with check (true);
create policy "public access" on narrative_events for all using (true) with check (true);
create policy "public access" on persona_evolution_log for all using (true) with check (true);

